 :root {
 --bg: #151519;
 --card-bg: rgba(22, 22, 26, 0.75);
 --line: rgba(255,255,255,0.06);
 --text: rgba(235, 235, 240, 0.9);
 --muted: rgba(235, 235, 240, 0.6);
 --accent: rgba(218, 185, 128, 0.9);
 --ui: ui-sans-serif, system-ui, -apple-system, sans-serif;
 --mono: ui-monospace, SFMono-Regular, Consolas, monospace;
 --head: "MaoKenWangFengYaSong", var(--ui);
 --body: "Nowar Sans TW", var(--ui);
 --r: 4px;
 }

 details.scene {
 max-width: 720px;
 margin: 20px auto;
 border: 1px solid var(--line);
 border-radius: var(--r);
 background: var(--card-bg);
 color: var(--text);
 overflow: hidden;
 backdrop-filter: blur(16px);
 -webkit-backdrop-filter: blur(16px);
 box-shadow: 0 4px 24px rgba(0,0,0,0.4);
 }

 details.scene > summary { list-style: none; }
 details.scene > summary::-webkit-details-marker { display: none; }

 summary.scene__head {
 cursor: pointer;
 position: relative;
 padding: 0;
 user-select: none;
 }

 .scene__hero {
 position: relative;
 aspect-ratio: 3 / 2;
 background: #0a0a0c;
 overflow: hidden;
 }

 .scene__img {
 width: 100%;
 height: 100%;
 object-fit: cover;
 opacity: 0.75;
 transition: opacity 0.4s ease, transform 0.8s cubic-bezier(0.2, 0, 0.2, 1);
 }

 summary.scene__head:hover .scene__img {
 opacity: 0.8;
 transform: scale(1.02);
 }

 /* Тот самый ОЧЕНЬ ЧУТЬ ЧУТЬ Lens Flare */
 .scene__flare {
 position: absolute;
 inset: 0;
 pointer-events: none;
 z-index: 2;
 background: 
  radial-gradient(circle at 15% 25%, rgba(255,255,255,0.04) 0%, transparent 15%),
  radial-gradient(circle at 12% 28%, rgba(218, 185, 128, 0.03) 0%, transparent 25%);
 mix-blend-mode: screen;
 }

 .scene__overlay {
 position: absolute;
 inset: 0;
 background:
  linear-gradient(90deg, rgba(0,0,0,0.8) 0%, rgba(0,0,0,0.4) 40%, transparent 100%),
  linear-gradient(180deg, transparent 70%, rgba(0,0,0,0.3) 100%);
 pointer-events: none;
 z-index: 1;
 }

 .scene__mist {
 position: absolute;
 inset: 0;
 width: 100%;
 height: 100%;
 pointer-events: none;
 opacity: 0.4;
 z-index: 1;
 }

 .scene__head-text {
 position: absolute;
 left: 0;
 top: 0;
 bottom: 0;
 width: 65%; /* Больше места для текста */
 display: flex;
 flex-direction: column;
 align-items: flex-start;
 justify-content: flex-end;
 padding: 20px 24px;
 gap: 4px;
 z-index: 3;
 }

 .scene__dt {
 font-family: var(--mono);
 font-size: 0.6rem; /* Меньше */
