 font-size: 1.15rem; /* Уменьшен размер */
 line-height: 1.2;
 color: #fff;
 text-shadow: 0 2px 10px rgba(0,0,0,0.5);
 }

 .scene__wx {
 font-family: var(--body);
 font-size: 0.8rem; /* Уменьшен размер */
 color: rgba(255,255,255,0.6);
 margin-top: 2px;
 }

 .scene__arrow {
 position: absolute;
 bottom: 14px;
 right: 14px;
 width: 24px;
 height: 24px;
 display: flex;
 align-items: center;
 justify-content: center;
 font-family: var(--mono);
 color: rgba(255,255,255,0.3);
 border: 1px solid rgba(255,255,255,0.1);
 border-radius: 50%;
 font-size: 0.6rem;
 transition: all 0.3s ease;
 z-index: 4;
 }

 details.scene[open] .scene__arrow { transform: rotate(180deg); }

 .scene__body {
 padding: 14px 20px 20px; /* Более компактные отступы */
 display: grid;
 gap: 14px;
 }

 .scene__atmo {
 margin: 0;
 font-family: var(--head);
 font-size: 0.95rem; /* Чуть меньше */
 color: rgba(255,255,255,0.8);
 line-height: 1.5;
 text-align: center;
 font-style: italic;
 opacity: 0.9;
 }

 .scene__section {
 padding-top: 12px; /* Компактнее */
 border-top: 1px solid var(--line);
 }

 .scene__title {
 font-family: var(--mono);
 font-size: 0.65rem;
 text-transform: uppercase;
 letter-spacing: 0.1em;
 color: var(--accent);
 margin: 0 0 10px 0;
 opacity: 0.7;
 }

 .kv {
 display: grid;
 grid-template-columns: 80px 1fr;
 gap: 4px 14px; /* Плотнее */
 font-size: 0.85rem;
 line-height: 1.4;
 align-items: baseline;
 }

 .k {
 font-family: var(--body);
 color: var(--muted);
 text-align: right;
 font-size: 0.8rem;
 }

 .v {
 font-family: var(--body);
 color: var(--text);
 }

 .v--mind {
 font-family: var(--head);
 color: #d0d0d0;
 font-style: normal; /* Убран курсив по просьбе */
 }

 .scene__recap {
 font-family: var(--body);
 font-size: 0.85rem;
 color: var(--muted);
 line-height: 1.6;
 white-space: pre-wrap;
 margin: 0;
 text-align: justify;
 }

 .scene__bar-wrap {
 display: flex;
 align-items: center;
 gap: 8px;
 }

 .scene__bar-bg {
 flex: 1;
 height: 2px;
 background: rgba(255,255,255,0.06);
 border-radius: 1px;
 overflow: hidden;
 max-width: 80px;
 }

 .scene__bar-fill {
 height: 100%;
 background: var(--accent);
 width: var(--val, 0%);
 box-shadow: 0 0 8px var(--accent);
 }

 @media (max-width: 500px) {
 .scene__head-text { width: 100%; }
 .kv { grid-template-columns: 1fr; gap: 2px; }
 .k { text-align: left; opacity: 0.5; margin-top: 4px; }
 }
</style>
