<script>
document.querySelectorAll('.scene__mist').forEach(canvas => {
 const ctx = canvas.getContext('2d');
 const parent = canvas.parentElement;
 let width, height;

 function resize() {
 width = parent.offsetWidth;
 height = parent.offsetHeight;
 canvas.width = width;
 canvas.height = height;
 }
 window.addEventListener('resize', resize);
 resize();

 const blobs = [];
 const blobCount = 3;

 for (let i = 0; i < blobCount; i++) {
 blobs.push({
  x: Math.random() * width,
  y: Math.random() * height,
  rx: width * (0.3 + Math.random() * 0.3),
  ry: height * (0.2 + Math.random() * 0.3),
  phaseX: Math.random() * Math.PI * 2,
  phaseY: Math.random() * Math.PI * 2,
  driftX: 0.0002 + Math.random() * 0.0003,
  driftY: 0.0001 + Math.random() * 0.0002,
  alpha: 0.02 + Math.random() * 0.02,
  breathSpeed: 0.0005 + Math.random() * 0.0005
 });
 }

 let t = 0;
 function draw() {
 ctx.clearRect(0, 0, width, height);
 t++;
 blobs.forEach(b => {
  const cx = b.x + Math.sin(t * b.driftX + b.phaseX) * width * 0.1;
  const cy = b.y + Math.cos(t * b.driftY + b.phaseY) * height * 0.05;
  const breath = 1 + Math.sin(t * b.breathSpeed) * 0.1;
  const curRx = b.rx * breath;
  const curRy = b.ry * breath;

  const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, Math.max(curRx, curRy));
  grad.addColorStop(0, `rgba(220, 215, 205, ${b.alpha})`);
  grad.addColorStop(1, 'rgba(200, 200, 195, 0)');

  ctx.save();
  ctx.translate(cx, cy);
  ctx.scale(curRx / Math.max(curRx, curRy), curRy / Math.max(curRx, curRy));
  ctx.translate(-cx, -cy);
  ctx.fillStyle = grad;
  ctx.beginPath();
  ctx.arc(cx, cy, Math.max(curRx, curRy), 0, Math.PI * 2);
  ctx.fill();
  ctx.restore();
 });
 requestAnimationFrame(draw);
 }
 draw();
});
</script>

